import React, { useState } from "react";

export default function FoodPage() {
  const [activeTab, setActiveTab] = useState("breakfast");

  const menu = {
    breakfast: [
      { id: 1, name: "Aloo Paratha", price: 40, emoji: "🥘" },
      { id: 2, name: "Poha", price: 30, emoji: "🍚" },
      { id: 3, name: "Bread Omelette", price: 35, emoji: "🍳" },
      { id: 4, name: "Idli Sambhar", price: 45, emoji: "🥄" },
    ],
    lunch: [
      { id: 5, name: "Masala Dosa", price: 50, emoji: "🥗" },
      { id: 6, name: "Biryani", price: 80, emoji: "🍛" },
      { id: 7, name: "Paneer Tikka", price: 90, emoji: "🍖" },
      { id: 8, name: "Butter Chicken", price: 95, emoji: "🍗" },
    ],
    snacks: [
      { id: 9, name: "Samosa", price: 20, emoji: "🥟" },
      { id: 10, name: "Pakora", price: 25, emoji: "🥙" },
      { id: 11, name: "Chai Tea", price: 15, emoji: "🍵" },
      { id: 12, name: "Vada Pav", price: 30, emoji: "🍢" },
    ],
  };

  const [cart, setCart] = useState({});

  const addItem = (item) => {
    setCart((prev) => ({
      ...prev,
      [item.id]: (prev[item.id] || 0) + 1,
    }));
  };

  const removeItem = (itemId) => {
    setCart((prev) => {
      const newCart = { ...prev };
      if (newCart[itemId] > 1) {
        newCart[itemId]--;
      } else {
        delete newCart[itemId];
      }
      return newCart;
    });
  };

  const cartTotal = Object.entries(cart).reduce((total, [itemId, qty]) => {
    const item = Object.values(menu)
      .flat()
      .find((i) => i.id === Number(itemId));
    return total + (item?.price || 0) * qty;
  }, 0);

  const cartCount = Object.values(cart).reduce((sum, qty) => sum + qty, 0);

  const tabs = [
    { id: "breakfast", label: "Breakfast", emoji: "🌅" },
    { id: "lunch", label: "Lunch", emoji: "☀️" },
    { id: "snacks", label: "Snacks", emoji: "🍿" },
  ];

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="glass-card p-8 space-y-2">
        <h1 className="text-3xl font-bold text-slate-900">🍽️ Food Order</h1>
        <p className="text-slate-600">Order meals from campus cafeteria</p>
      </div>

      {/* Tabs */}
      <div className="glass-card p-4 flex gap-4 flex-wrap">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`px-6 py-3 rounded-lg font-semibold transition-all ${
              activeTab === tab.id
                ? "tab-active bg-blue-100 text-blue-700"
                : "tab-inactive hover:bg-slate-100"
            }`}
          >
            <span>{tab.emoji}</span> {tab.label}
          </button>
        ))}
      </div>

      {/* Menu Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {menu[activeTab].map((item) => {
          const qty = cart[item.id] || 0;
          return (
            <div key={item.id} className="glass-card p-6 space-y-4">
              <div className="text-5xl text-center">{item.emoji}</div>
              <div className="space-y-1 text-center">
                <h3 className="font-bold text-slate-900">{item.name}</h3>
                <p className="text-lg font-bold text-blue-600">₹{item.price}</p>
              </div>

              {qty === 0 ? (
                <button
                  onClick={() => addItem(item)}
                  className="btn-primary w-full"
                >
                  + Add
                </button>
              ) : (
                <div className="flex items-center justify-between gap-2">
                  <button
                    onClick={() => removeItem(item.id)}
                    className="flex-1 px-3 py-2 bg-red-100 text-red-600 rounded-lg font-bold hover:bg-red-200"
                  >
                    −
                  </button>
                  <span className="flex-1 text-center font-bold text-slate-900">
                    {qty}
                  </span>
                  <button
                    onClick={() => addItem(item)}
                    className="flex-1 px-3 py-2 bg-green-100 text-green-600 rounded-lg font-bold hover:bg-green-200"
                  >
                    +
                  </button>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Cart Summary */}
      {cartCount > 0 && (
        <div className="fixed bottom-6 right-6 glass-card p-6 space-y-4 w-96 max-w-md">
          <div className="space-y-2">
            <p className="font-semibold text-slate-900">
              🛒 Cart • {cartCount} item{cartCount > 1 ? "s" : ""}
            </p>
            <p className="text-2xl font-bold text-blue-600">Total: ₹{cartTotal}</p>
          </div>
          <button className="btn-primary w-full">Place Order →</button>
        </div>
      )}
    </div>
  );
}
